"""
mkt-original: Habakkuk ch1-3 — comprehensive Hebrew philological commentary (55 verses).
Ch2:v4 already exists; merge_comm will not overwrite it.
Run: python3 scripts/zc-original-habakkuk-1-3.py
"""
import json, pathlib

ROOT = pathlib.Path(__file__).parent.parent


def load_comm(source, book):
    p = ROOT / 'data' / 'commentary' / source / f'{book}.json'
    return json.loads(p.read_text()) if p.exists() else {}


def save_comm(source, book, data):
    p = ROOT / 'data' / 'commentary' / source / f'{book}.json'
    p.parent.mkdir(parents=True, exist_ok=True)
    p.write_text(json.dumps(data, ensure_ascii=False, indent=2))
    print(f'  wrote {p.relative_to(ROOT)}')


def merge_comm(existing, new_data):
    # Never overwrite — only fill gaps
    for ch, verses in new_data.items():
        if ch not in existing:
            existing[ch] = {}
        for v, text in verses.items():
            if v not in existing[ch]:
                existing[ch][v] = text


DATA = {
    "1": {
        "1": "<p><strong>hamasa asher chazah Chavaquq hanavi</strong>: 'The oracle that Habakkuk the prophet saw.' The term <em>massa</em> (H4853, oracle/burden) is used for prophetic declarations of judgment — the word comes from the root <em>nasa</em> (to lift/carry), so the oracle is both 'lifted up' and a 'burden.' The verb <em>chazah</em> (saw/perceived, H2372) is the same root as <em>chazon</em> (vision) — prophetic reception is portrayed as a kind of seeing. Habakkuk is unique in that the oracle he 'saw' is largely composed of his own complaints to YHWH and YHWH's replies — a two-way dialogue rather than a unilateral proclamation. The name Habakkuk (<em>Chavaquq</em>, H2265) may derive from the verb <em>chavaq</em> (to embrace, H2263) — 'the one who embraces' or perhaps from an Akkadian plant name.</p>",

        "2": "<p><strong>ad anatah YHWH shivati velo tishma</strong>: 'O LORD, how long shall I cry for help, and you will not hear?' The opening question establishes the book's theological problem: prophetic complaint (lament) addressed directly to YHWH. The verb <em>za'aqti</em> (I cry, H2199) is the standard distress-cry that YHWH is supposed to answer (Exod 3:7 — YHWH heard the cry of the Israelites in Egypt). Habakkuk's complaint is that this standard mechanism has broken down: he cries, but YHWH does not hear. <em>Chamas</em> (violence, H2555) — the keyword introduced here and repeated through the book — is the characteristic sin of unjust power (Gen 6:11; Ps 72:14). The prophet is overwhelmed by violence and YHWH seems inactive.</p>",

        "3": "<p><strong>lama tasimeni raot veaval veshod veChamas lenegdi</strong>: 'Why do you make me see iniquity, and why do you idly look at wrong? Destruction and violence are before me; strife and contention arise.' The direct address 'why do you make me see' (<em>lama tasimeni raot</em>) — YHWH is not merely permitting evil but apparently compelling the prophet to witness it. <em>Aven</em> (iniquity/evil, H205) and <em>amal</em> (toil/trouble, H5999) are paired here and in several psalms of complaint. <em>Riv</em> (strife/lawsuit, H7379) and <em>madon</em> (contention, H4066) suggest the failure of the legal system — the dispute-resolution mechanisms of the covenant community have broken down.</p>",

        "4": "<p><strong>al ken tapug Torah velo yetze lanetzach mishpat</strong>: 'So the law is paralyzed, and justice never goes forth.' The Torah (<em>torah</em>, H8451) is described as <em>pugah</em> (numb/benumbed/paralyzed, from <em>pug</em> = to grow numb/cold, H6313) — a vivid metaphor: the covenant instruction has lost its ability to function, like a limb that has gone numb. <em>Mishpat</em> (justice, H4941) 'never goes forth' (<em>lo yetze... lanetzach</em>) — the legal process produces no just outcome. <em>Ki rasha maktir et hatzaddik</em> — 'for the wicked surround the righteous, therefore justice goes forth perverted (<em>meukkal</em>, twisted/bent).' The root <em>aqal</em> (H5791, to twist/distort) describes justice deformed by power.</p>",

        "5": "<p><strong>reu vagoyim vehabitu vehitamahu tamahu</strong>: 'Look among the nations, and see; wonder and be astounded. For I am doing a work in your days that you would not believe if told.' YHWH's first answer redirects the prophet's gaze to the nations (<em>goyim</em>). The fourfold imperative (look, see, wonder, be astounded) escalates the intensity of the divine announcement. <em>Poal po'el biyemeichem</em> (doing a work in your days) — YHWH is already at work in the geopolitical sphere. Paul quotes v5 in Acts 13:41 as a warning to those who reject the gospel: the 'incredible work' YHWH was doing through Babylon becomes a type of the 'incredible work' YHWH was doing in the resurrection — both defy expectation.</p>",

        "6": "<p><strong>ki hineni meqim et haKasdim hagoy hamar vehanimer</strong>: 'For behold, I am raising up the Chaldeans, that bitter and hasty nation, who march through the breadth of the earth, to seize dwellings not their own.' <em>Kasdim</em> (Chaldeans/Babylonians, H3778) — the Neo-Babylonian Empire under Nabopolassar and Nebuchadnezzar II was the rising superpower of Habakkuk's day (late 7th century BCE). <em>Marar</em> (bitter, H4751) and <em>maher</em> (swift/hasty, H4116) — the two adjectives characterize Babylonian warfare as both aggressive and rapid. The verb <em>meqim</em> (I am raising up) — the same vocabulary YHWH uses for raising up judges (Judg 2:16) — is applied here to a pagan empire, demonstrating YHWH's sovereign use of all nations as instruments.</p>",

        "7": "<p><strong>ayom veNora hu memenu mishpato uses'eto yetze</strong>: 'They are dreaded and fearsome; their justice and dignity go forth from themselves.' The Babylonians are not merely powerful but self-legislating — their law (<em>mishpat</em>) proceeds from themselves rather than from YHWH. This self-referential authority is the characteristic of imperial power that opposes YHWH's sovereignty: they define right and wrong, justice and honor, by their own standards. The verse sets up the theological problem: YHWH uses a nation whose very worldview is idolatrous self-sovereignty as the instrument of judgment on his own people.</p>",

        "8": "<p><strong>veqalu mishenem usim mishoal zevavihem</strong>: 'Their horses are swifter than leopards, more fierce than the evening wolves.' The war-horse imagery (horses <em>qalu</em> = swift, H7043; <em>chadu</em> = fierce, H2300) builds a portrait of irresistible military force. <em>Ze'evei erev</em> (evening wolves, H2061) — wolves hunting at dusk when they are most active and dangerous. The Babylonian cavalry was renowned in the ancient Near East; Assyrian and Babylonian reliefs confirm the image of swift horse-mounted armies. <em>Ufashu parashav</em> — 'their horsemen spread out' — the flanking maneuver that characterized Babylonian military tactics.</p>",

        "9": "<p><strong>kulo levias yavo megammat peneihem qadima</strong>: 'They all come for violence, all their faces forward.' The word <em>megammat</em> (H4041) is uncertain — possibly 'eagerness/striving' or related to the root for 'collective/mass.' The Babylonian advance is single-minded: <em>kuloh levias</em> (all of it for violence) — <em>chamas</em> appears again (cf. v2), now ascribed to the Babylonians as the instrument of judgment against Judah's own violence. <em>Veyaspeh ka-chol shevi</em> — 'he gathers captives like sand' — the simile of sand for incalculable numbers (cf. Gen 22:17) applied to the Babylonian mass deportations confirmed by archaeology.</p>",

        "10": "<p><strong>vehu bamelakim yitkalal verozenim mishchaq lo</strong>: 'He scoffs at kings, and rulers are a laughingstock to him.' The Babylonian king's attitude to other monarchs: <em>yitkalal</em> (he scoffs/mocks, H7046) — the root of <em>qalal</em> (to treat lightly/despise). <em>Rozenim mishchaq lo</em> (rulers are a laughingstock to him) — the political humiliation of conquered kings was a standard feature of Babylonian imperial propaganda, documented in the Babylonian Chronicle. <em>Vehu kol mivtzar yischaq vayisfor afar vayilkededah</em> — 'he laughs at every fortress; he heaps up earth and takes it.' Siege-ramp construction (heaping up earth against walls) is confirmed archaeologically at multiple sites conquered by Nebuchadnezzar.</p>",

        "11": "<p><strong>az chalaf ruach vayaavor veyashem zu kocho le'elohav</strong>: 'Then he sweeps by like the wind and goes on, guilty men, whose own might is their god.' The verse concludes the Babylonian portrait with a theological verdict: <em>zu kocho le'elohav</em> — 'this/he whose strength is his god.' The Babylonian deification of military power is the ultimate idolatry — making one's own capabilities the object of ultimate trust. This is the sin that will eventually destroy Babylon (2:4-5, 18-20): the proud man who makes himself his own god will fall by the very principle he lives by.</p>",

        "12": "<p><strong>halo atta miqqedem YHWH elohai qedoshi lo namut</strong>: 'Are you not from everlasting, O LORD my God, my Holy One? We shall not die.' Habakkuk's second complaint begins with a confession: <em>miqqedem</em> (from everlasting, H6924) — YHWH's eternity as the ground of confidence. <em>Qedoshi</em> (my Holy One, H6918) — the title used extensively by Isaiah for YHWH; holiness (<em>qedushah</em>) means being set apart, transcendent, and morally pure. The confession 'we shall not die' (<em>lo namut</em>) is the foundation of Habakkuk's subsequent question: if YHWH is eternal and holy, how can he use a more wicked nation to punish a less wicked one? The word <em>lemos'ath</em> (for judgment/correction, H4941) — 'You have ordained them as a judgment'; this is Habakkuk's grudging acknowledgment of divine purpose.</p>",

        "13": "<p><strong>tahorah einayim mire'ot ra vehabet el amal lo tuchal</strong>: 'You who are of purer eyes than to see evil and cannot look at wrong.' The theological core of Habakkuk's complaint: YHWH's holiness (<em>tahorah einayim</em>, pure eyes — the eyes of the Holy One cannot endure the sight of evil) creates a logical problem when YHWH uses evil Babylon as his instrument. <em>Lama tabbit bogedim tacharish bivla rasha tzaddik mimenu</em> — 'why do you look idly at traitors and remain silent when the wicked swallows up the man more righteous than he?' The comparative 'more righteous than he' (<em>tzaddik mimenu</em>) is the crux: Habakkuk does not claim Israel is innocent, only relatively more righteous than Babylon. YHWH's answer in ch2 addresses this directly.</p>",

        "14": "<p><strong>vataaseh adam kidgei hayam kereems lo moshel bo</strong>: 'You make mankind like the fish of the sea, like crawling things that have no ruler.' The fish-and-crawling-things simile for humanity under Babylonian domination extends the prophetic critique: like fish with no shepherd, people are swept up in the nets of the powerful. <em>Kidgei hayam</em> (like fish of the sea) — the same image Ezekiel uses for Egypt's Pharaoh as a great dragon in the Nile (Ezek 29:3-5); Habakkuk applies it to all humanity under imperial domination. The absence of a ruler (<em>lo moshel bo</em>) is both a description of helplessness and an implicit complaint: where is the divine Ruler?</p>",

        "15": "<p><strong>kulo bechangah he'ala</strong>: 'He brings all of them up with a hook.' The fishing imagery continues through vv15-17: hook (<em>changah</em>, H2443), net (<em>cherem</em>, H2764), and dragnet (<em>mikhmoret</em>, H4365) — three implements of mass capture. The Babylonian is the fisherman; nations are the catch. <em>Yagel veyismach</em> — 'he rejoices and is glad' — over the mass catch, the enemy celebrates his conquests with religious rites dedicated to his weapons (v16: he sacrifices to his net).</p>",

        "16": "<p><strong>al ken yezabech le-cheremoh viqqater lemikhmartoh</strong>: 'Therefore he sacrifices to his net and makes offerings to his dragnet.' The Babylonian's idolatry is the worship of military technology: his net (= his military apparatus) becomes his god. <em>Asher bashmen chelqo umaachalov bariah</em> — 'for by them his portion is fat, and his food is rich.' The religious sanction of conquering power as divine favor is documented in Babylonian royal inscriptions: victories are thanksgivings to Marduk and the divine warrior gods. Habakkuk exposes this as the worship of tools — the net and dragnet given the honor that belongs to YHWH.</p>",

        "17": "<p><strong>hal al ken yariq cheremoh vetamid laharog goyim lo yachmol</strong>: 'Is he then to keep on emptying his net and mercilessly killing nations forever?' The chapter ends with Habakkuk's second unanswered question: Will this go on indefinitely? The word <em>tamid</em> (continually/always, H8548) — the same word used for the daily (<em>tamid</em>) offering in the temple, now applied to the perpetual slaughter of nations. <em>Lo yachmol</em> (without mercy) — the absence of <em>chemah</em> (compassion/mercy). The question is not rhetorical despair but urgent prayer: this cannot be YHWH's permanent arrangement.</p>"
    },
    "2": {
        "1": "<p><strong>al mishmarti e'emod vaetiyatzevah al matzor</strong>: 'I will take my stand at my watchpost and station myself on the tower.' Habakkuk's posture between complaints and answers is watchman-theology: <em>mishmar</em> (watch/guard post, H4931) and <em>matzor</em> (watchtower, H4692) are military observation positions. The prophet-as-watchman is developed in Ezek 3:17 and 33:7 — the prophet stationed to warn the people. Here Habakkuk stations himself to receive YHWH's response. <em>Mah yadaber bi umai ashiv al tokachti</em> — 'to see what he will say to me, and what I will answer concerning my complaint.' The word <em>tokachti</em> (my reproof/complaint, H8433) acknowledges that the prophet's complaint may itself require a divine correction.</p>",

        "2": "<p><strong>vaya'aneni YHWH vayomer kotov chazon vevaer al haluachot</strong>: 'And the LORD answered me: Write the vision; make it plain on tablets, so he may run who reads it.' The divine response begins with an inscription command: write (<em>ketov</em>), make plain (<em>baer</em>, H874 = to engrave/inscribe clearly). <em>Al haluachot</em> (on tablets) — the same material as the stone tablets of the Ten Commandments (Exod 24:12; 32:15-16), suggesting this vision has Torah-like permanence and authority. <em>Lemaan yarutz qore vo</em> — 'so that he may run who reads it' — the inscription is meant to be readable at a glance by a runner (messenger on the road), or perhaps the phrase means 'the reader of it should run' — flee or act urgently on what is written.</p>",

        "3": "<p><strong>ki od chazon lamoled veyfuach laqetz velo yechazev</strong>: 'For still the vision awaits its appointed time; it hastens to the end — it will not lie.' The theology of delayed fulfillment: <em>moled</em> (appointed time/birth-moment, H4150 — the same root as <em>moed</em>, the fixed appointed feast times) indicates that divine fulfillment comes at the time YHWH has precisely set. <em>Im yitmahmeha chakeh lo</em> — 'if it seems slow, wait for it; it will surely come, it will not delay.' The author of Hebrews quotes v3-4 in 10:37-38 as encouragement to endure: 'For yet a little while, and the coming one will come and will not delay.' The 'coming one' is Christ — Habakkuk's 'vision awaiting its appointed time' becomes the pattern for the parousia.</p>",

        "5": "<p><strong>veaf ki hayayin boged gever yahir velo yinaveh</strong>: 'Moreover, wine is a traitor, an arrogant man who is never at rest.' The woe-cycle (2:6-20) is introduced by a general statement about the proud and greedy. <em>Hayin boged</em> (wine is a traitor) — wine as the metaphor for Babylon's insatiable appetite (cf. Jer 51:7: Babylon is a gold cup in YHWH's hand that made all the earth drunk). <em>Asher hirchiv kishol nafsho vehu kamavet velo yisba</em> — 'who enlarges his desire like Sheol, and like death he never has enough.' The comparison to Sheol and death for imperial appetite is striking: Sheol (the underworld) is never satisfied (Prov 27:20; 30:15-16) — the empire that keeps consuming nations is compared to the realm of death's insatiability.</p>",

        "6": "<p><strong>halo eleh kulo mashal alav yisa umelitzah chidot lo yomar</strong>: 'Shall not all these take up their taunt against him, with scoffing and riddles for him, and say...' The five woes of ch2 (vv6, 9, 12, 15, 19) are structured as a taunt-song (<em>mashal</em>, H4912) — a wisdom form in which the tables are turned on the oppressor. <em>Hoy hamarbeh lo asher ad matai</em> — 'Woe to him who heaps up what is not his own — for how long? — and loads himself with pledges.' The first woe addresses economic exploitation through debt-pledge (<em>avitit</em>, H5671 = thick clay = heavy debt). The rhetorical question 'for how long?' echoes Habakkuk's own complaint in 1:2.</p>",

        "7": "<p><strong>halo petom yaqumu nashecheicha veqatzu mezazeicha vehayita limshisot lamo</strong>: 'Will not your debtors suddenly arise, and those who make you tremble wake up? Then you will be their prey.' The reversal: the creditor becomes the debtor, the oppressor becomes the prey. <em>Nashecheicha</em> (your creditors/biters, from <em>nashach</em> = to bite/charge interest, H5391) — the bitter word-play: those who took interest ('biters') will themselves rise up against their oppressor. The economic exploitation by debt will produce the very rebellion that destroys the empire.</p>",

        "8": "<p><strong>ki atta shallota goyim rabbim yishalluchacha kol yeter amim</strong>: 'Because you have plundered many nations, all the remnant of the peoples shall plunder you.' The lex talionis at the international scale: the nation that plundered will be plundered (<em>shallota... yishalluchacha</em> — same root <em>shalal</em>). <em>Midam adam uchamas eretz qiryah vekhol yoshevei vah</em> — 'for the blood of man and violence to the earth, to cities and all who dwell in them.' The three charges — blood, violence to land, violence to cities — are the comprehensive indictment of imperial conquest. <em>Chamas</em> (violence) appears again: the same sin Habakkuk complained about in Judah (1:2-3) is now the grounds for Babylon's judgment.</p>",

        "9": "<p><strong>hoy botze betzah ra leveito lashum bamarom qinno</strong>: 'Woe to him who gets evil gain for his house, to set his nest on high, to be safe from the reach of harm!' The second woe addresses economic exploitation for self-protection. <em>Betzah ra</em> (evil gain/unjust profit, H1214 + H7451) — the term <em>batzah</em> covers both cutting/slicing and profiteering (Jer 6:13: from prophet to priest, every one deals falsely / profits unjustly). <em>Lashum bamarom qinno</em> — 'to set his nest on high' — the eagle-nest image (cf. Obad 4) for impregnable security through wealth. The woe declares this strategy ultimately futile.</p>",

        "10": "<p><strong>yatzata bosheth lebeitecha qetzot amim rabbim</strong>: 'You have devised shame for your house by cutting off many peoples.' The verb <em>yatzata</em> (you have counseled/devised, H3289) — the planning that was intended for security (<em>lashum bamarom</em>, v9) has actually produced shame. <em>Bosheth</em> (shame/disgrace, H1322) is the reversal of the honor (<em>kavod</em>) the empire sought. <em>Vechoteh nafsho</em> — 'and have forfeited your life' — the soul (<em>nefesh</em>) lost in the pursuit of security for the house (<em>bayit</em>). The irony: seeking to protect the house by exploiting nations, you destroy both the house and yourself.</p>",

        "11": "<p><strong>ki even mizir tizaq vekaphis metz aneha</strong>: 'For the stone will cry out from the wall, and the beam from the woodwork respond.' The building materials of the house built on unjust gain will testify against its builder. This is the language of creation as moral witness: even inanimate materials have a voice to accuse. The NT parallel: Luke 19:40 (the stones would cry out), where Jesus applies creation-witness language to the acclaim due to the messianic king entering Jerusalem. Romans 8:19-22 (creation groaning) develops the same theme of creation testifying against human sin.</p>",

        "12": "<p><strong>hoy boneh ir bedamim vekonen qiryah beavel</strong>: 'Woe to him who builds a town with blood and founds a city on iniquity!' The third woe addresses the city built on violence. <em>Damim</em> (blood, H1818) and <em>avel</em> (iniquity/wickedness, H5766) are the twin foundations of the imperial city. The specific application to Babylon (whose construction projects used forced labor from conquered peoples) is historically precise. Jer 51:58 repeats the charge: 'Babylon's broad walls shall be leveled to the ground, and her high gates shall be burned with fire; the peoples labor for nothing.' The city that seems impregnable is built on morally unstable ground.</p>",

        "13": "<p><strong>halo hineh me'et YHWH tzvaot veyig'u amim bedei esh velaomim bedei rik yia'efu</strong>: 'Behold, is it not from the LORD of hosts that peoples labor merely for fire, and nations weary themselves for nothing?' The woe is grounded in YHWH's sovereign irony: the labor of the nations in service of Babylon is ultimately purposeless — <em>ledei esh</em> (for fire) and <em>ledei rik</em> (for nothing/emptiness). All of Babylon's building projects will be consumed by the same fire their conquest brought on others. <em>YHWH tzvaot</em> (LORD of hosts) — the military title underscores that the divine commander outranks the Babylonian empire commander.</p>",

        "14": "<p><strong>ki timale ha'aretz ladaat et kevod YHWH kamayim yechassu al hayam</strong>: 'For the earth will be filled with the knowledge of the glory of the LORD as the waters cover the sea.' This verse, the centerpiece of the woe-cycle, is the positive eschatological vision that grounds all the judgments: YHWH's glory will ultimately fill the earth as universally as water fills the ocean. The parallel in Isa 11:9 (the messianic kingdom) and Num 14:21 (YHWH's oath) confirms this is an eschatological absolute. <em>Da'at et kevod YHWH</em> (knowledge of the glory of the LORD) — not merely intellectual knowledge but experiential recognition of YHWH's presence and character filling all creation.</p>",

        "15": "<p><strong>hoy mashqeh reahuhu mesapech chamato af shaker</strong>: 'Woe to him who makes his neighbors drink — you pour out your wrath and make them drunk, in order to gaze at their nakedness.' The fourth woe uses the cup of intoxicating wine as a metaphor for imperial humiliation of conquered peoples. <em>Mesapech chamato</em> (pouring out his wrath/poison) — <em>chamah</em> (H2534) covers both wrath and the heat of wine/poison. The connection to the cup of YHWH's wrath (Jer 25:15-17; Rev 14:10; 16:19) is deliberate: Babylon forces the cup on others; YHWH will force the cup on Babylon.</p>",

        "16": "<p><strong>savata qalon mekavod shete gam atta vehare'el</strong>: 'You will have your fill of shame instead of glory. Drink, yourself, and show your uncircumcision!' The reversal of the fourth woe: the one who made others drink will drink himself. <em>Qalon mekavod</em> (shame instead of glory) — the <em>kavod-qalon</em> antithesis is fundamental to biblical theology: the one who seeks glory through shame-infliction will receive shame. <em>Tassov aleicha kos yamin YHWH</em> — 'the cup in the LORD's right hand will come around to you' — the eschatological cup of judgment that the oppressor has been forcing on others will turn and be forced on the oppressor.</p>",

        "17": "<p><strong>ki chamas Levanon yechassecha veshood behemot yechitelan</strong>: 'The violence done to Lebanon will overwhelm you, and the destruction of the beasts will terrify you.' The environmental dimension of the woe: the Babylonians plundered the cedar forests of Lebanon (confirmed in Babylonian royal inscriptions — Nebuchadnezzar boasts of bringing cedar from Lebanon). <em>Chamas Levanon</em> (violence to Lebanon) — the deforestation and ecological destruction wrought by imperial logging and building projects. The animal kingdom (<em>behemot</em>) destroyed by the Babylonians will haunt them. The same charge appears in vv8 and 12 — blood, violence, destruction — forming a refrain of ecological and humanitarian indictment.</p>",

        "18": "<p><strong>mah ho'il pesel ki pesalo yotzero massekhah umorah shaqer</strong>: 'What profit is an idol when its maker has shaped it, a metal image, a teacher of lies?' The fifth woe (vv18-20) addresses idolatry directly. The polemic against idols uses the standard wisdom argument: the idol is <em>pesel</em> (carved image, H6459) shaped by its maker (<em>yotzero</em>) — the creator of the idol is human, therefore the idol is not god. <em>More shaqer</em> (teacher of lies, H8267) — the idol teaches what is false about ultimate reality. The idol-maker trusts in his own product (<em>vatach yotzero alav</em>) — the ultimate futility: trusting in something you yourself made.</p>",

        "19": "<p><strong>hoy omer laaetz haqitza uri leeven dumam</strong>: 'Woe to him who says to a wooden thing, Awake; to a silent stone, Arise!' The fifth woe is the woe against the idol. Calling a piece of wood or stone to 'awake' (<em>haqitza</em>) and 'arise' (<em>uri</em>) — the same vocabulary used to awaken YHWH himself in the psalms of lament (Ps 44:23; 78:65) — is applied to the mute idol. The idol is <em>hua yoru</em> (it will teach) — but covered in gold and silver, it has no breath (<em>ruach ein beqirbo</em>). The <em>ruach</em> (spirit/breath/wind) that animates everything is absent from the idol. 'There is no breath in it' is the ultimate verdict on all idolatry: what is worshipped is inanimate.</p>",

        "20": "<p><strong>vaYHWH beheikhal qodsho has mikol haeretz lefanav</strong>: 'But the LORD is in his holy temple; let all the earth keep silence before him.' The great contrast to the five woes and the lifeless idols: YHWH is in his holy temple (<em>heikhal qodsho</em>) — the earthly temple (Jerusalem) as the throne-room of the cosmic king. <em>Has mikol haeretz lefanav</em> — 'hush before him, all the earth.' The verb <em>has</em> (hush/silence, H2013) demands a reverential silence that is the opposite of idol-worship's futile appeals. The verse is the hinge of the book: from the noise of complaint and woe to the silence of awe before the enthroned YHWH. Zeph 1:7 and Zech 2:13 use the same formula. The universe falls silent before the one who alone is truly alive and sovereign.</p>"
    },
    "3": {
        "1": "<p><strong>tefilah leChavaquq hanavi al shigionot</strong>: 'A prayer of Habakkuk the prophet, according to Shigionoth.' Chapter 3 is a psalm — the only prophet's book to contain one embedded as an integral unit. <em>Shigionoth</em> (H7692, plural of <em>shiggayon</em>) appears only here and Ps 7:1 — the term may indicate a passionate, wandering meter or a musical mode associated with intense lament/praise. The chapter is structured as a theophanic hymn: introduction (vv1-2), theophanic vision of YHWH the warrior (vv3-15), and personal response of trust (vv16-19). The psalm has a superscription and a postscript ('to the choirmaster, with stringed instruments,' v19) — indicating liturgical use in the temple.</p>",

        "2": "<p><strong>YHWH shamati shimecha yareiti</strong>: 'LORD, I have heard the report of you, and your work, O LORD, do I fear.' The prophet's opening is a confession of awe at YHWH's past deeds (<em>shamati shimecha</em>, 'I heard your report/fame') — the reports of the Exodus and the conquest. <em>Beyerev shanim chayehu</em> — 'In the midst of the years revive it' — the prayer for YHWH to repeat his historic saving acts in the present crisis. <em>Beqetzef rechem tizkor</em> — 'in wrath remember mercy' — the tension at the heart of the book: divine wrath is real and the Babylonian judgment is coming, but Habakkuk prays that YHWH's foundational characteristic (<em>rachem</em>, compassion) will not be forgotten even in the midst of judgment.</p>",

        "3": "<p><strong>Eloah miteman yavo veqadosh mehar Paran selah</strong>: 'God came from Teman, and the Holy One from Mount Paran. Selah.' The theophanic vision begins with the classic geography of the Sinai theophany: Teman (in Edom, south of Judah) and Mount Paran (in the Sinai/Negev region) are both associated with YHWH's original appearance to Israel at Sinai (Deut 33:2; Judg 5:4-5). The theophany is not a new divine arrival but a <em>re</em>-appearance of the same YHWH who came at Sinai. <em>Kissa shamayim hodo</em> — 'his glory covered the heavens' — the divine <em>kavod</em> (glory) is so vast it fills the sky. The <em>selah</em> marking (as in the Psalms) may indicate a musical interlude or a pause for reflection.</p>",

        "4": "<p><strong>venogah kaor tihyeh qarnayim miyado lo</strong>: 'His brightness was like the light; rays flashed from his hand, and there he veiled his power.' The theophanic light-imagery: <em>nogah</em> (brightness/radiance, H5051) and <em>or</em> (light) combined — the blinding radiance of divine presence. <em>Qarnayim miyado lo</em> — 'rays from his hand' — the word <em>qarnayim</em> (H7161) means both 'horns' and 'rays of light' (the same ambiguity as Exod 34:29-35, where Moses's face 'shone' or had 'horns of light' after the theophany — hence Michelangelo's horned Moses). <em>Vesham chevyon uzoh</em> — 'there his power was hidden' — the paradox: the brilliance reveals and conceals simultaneously; the full power of YHWH is veiled even in theophany.</p>",

        "5": "<p><strong>lefanav yelech daver veyetze reshef leraglav</strong>: 'Before him went pestilence, and plague followed at his heels.' The divine warrior is accompanied by his escort: <em>dever</em> (pestilence, H1698) and <em>reshef</em> (plague/burning disease, H7565) — also the names of Canaanite plague-deities demythologized in OT theology to become YHWH's servants. The cosmic battle imagery: YHWH's advance is preceded by forces that clear the way. In the Exodus narrative, the plagues were precisely this — YHWH's advance guard defeating Egypt before the main act of the sea crossing. The same theophanic warrior comes again in Hab 3.</p>",

        "6": "<p><strong>amad vaymoded eretz raa vayyater goyim</strong>: 'He stood and measured the earth; he looked and shook the nations.' The divine warrior surveying the battlefield: <em>amad vayamoded</em> (stood and measured/shook) — the measuring (<em>madad</em>) may be the act of staking out territory for conquest, or the shaking (alternate reading of <em>vayamoded</em> from <em>mud</em>). <em>Vayitpatzetzu harerei ad</em> — 'then the eternal mountains were scattered' — the most permanent features of the landscape (the everlasting mountains) are shattered by YHWH's presence. The geological stability of mountains serves as the standard OT metaphor for permanence; their shattering before YHWH is the strongest statement of his sovereignty over creation.</p>",

        "7": "<p><strong>tachat aven raiti ahalot Kushsan yirgezun yeri'ot eretz Midyan</strong>: 'I saw the tents of Cushan in affliction; the curtains of the land of Midian did tremble.' Cushan and Midian are south-eastern peoples associated with the Sinai wilderness period (Midian appears extensively in the Exodus narrative — Moses's father-in-law is Midianite). Their trembling before YHWH's advance rehearses the nations' fear at the original theophany (Exod 15:14-16: the peoples heard, they trembled; dread fell on the inhabitants of Canaan). The Hab 3 theophany re-enacts the Exodus theophany at cosmic scale.</p>",

        "8": "<p><strong>havoraham YHWH bineharim af YHWH bineharim</strong>: 'Was your wrath against the rivers, O LORD? Was your anger against the rivers, or your indignation against the sea?' The repeated question about YHWH's action against rivers and sea draws on the creation combat myth (the divine warrior defeating the waters at creation, Ps 74:13-17; 89:9-10) and the Exodus sea-crossing (Exod 14-15). <em>Ki tirkav al susecha</em> — 'when you rode on your horses, on your chariot of salvation' — YHWH as the divine charioteer (cf. Ps 68:17: the chariots of God are tens of thousands). The 'chariot of salvation' (<em>merkevotecha yeshuah</em>) links the theophanic vision directly to the book's central concern: divine salvation for the people.</p>",

        "9": "<p><strong>erya teria qashetecha shevuot mattot omer selah</strong>: 'You stripped the sheath from your bow, calling for many arrows. Selah.' The divine warrior prepares for battle: the bow unsheathed, the arrows readied. <em>Shevuot mattot omer</em> — 'the oaths of the tribes, yes, the word' — YHWH's battle preparation is grounded in covenant oath to the tribes of Israel. <em>Neharot tebaqqa eretz</em> — 'you split the earth with rivers' — the cosmic battle creates rivers where there were none (cf. Exod 17:6, water from the rock; Ps 78:15-16).</p>",

        "10": "<p><strong>rauchah vayachilu harim zorem mayim avar natan tehom qolo</strong>: 'The mountains saw you and writhed; the raging waters swept on; the deep gave forth its voice; it lifted its hands on high.' The personification of the cosmic forces: mountains writhe (<em>yachilu</em>, the verb for labor pains — the same mountains that 'tremble like a woman in labor' in Isa 13:8), waters surge, the <em>tehom</em> (the deep/abyss, H8415 — the primordial ocean of Gen 1:2) lifts its hands in surrender. The posture of submission from creation itself before the divine warrior.</p>",

        "11": "<p><strong>shemesh yerach amad zevulah leor chitzeicha yehalekhu</strong>: 'The sun and moon stood still in their place at the light of your arrows as they sped, at the flash of your glittering spear.' The theophany evokes the Joshua 10:12-13 solar standstill at Gibeon — the day the sun and moon stopped to allow Israel's victory. YHWH's theophanic arrows (<em>chitzeicha</em>) produce a flash of light that overshadows even the sun. The cosmic standstill before divine power: the celestial timekeepers are suspended at YHWH's battle initiative.</p>",

        "12": "<p><strong>bezaem titzad eretz beaf tedush goyim</strong>: 'In fury you marched through the earth; in anger you trampled the nations.' The divine warrior in full battle advance: <em>titzad</em> (marched/strode) with <em>zaem</em> (fury/indignation, H2195) and <em>tedush</em> (trampled, from <em>dush</em> = to thresh, H1758). The threshing/trampling metaphor for divine judgment is common in the prophets (Isa 41:15; Mic 4:13; Amos 1:3). Nations are the grain threshed by the divine warrior in his anger.</p>",

        "13": "<p><strong>yatzata leyeshua amecha leyeshua et meshichecha</strong>: 'You went out for the salvation of your people, for the salvation of your anointed.' The purpose of the theophanic battle is now declared: <em>yeshua amecha</em> (salvation of your people) and <em>yeshua et meshichecha</em> (salvation of your anointed). <em>Meshichecha</em> (your anointed, H4899) — the same root as <em>mashiach</em> (Messiah/Christ). In the immediate context this refers to the Davidic king (YHWH's anointed); in the canonical context, it points forward to the ultimate Anointed One. <em>Machatzta rosh mibbeit rasha</em> — 'you crushed the head of the house of the wicked' — the head-crushing echoes Gen 3:15.</p>",

        "14": "<p><strong>nakapta bematav rosh peruzav</strong>: 'You pierced with his own arrows the heads of his warriors.' The reversal: the enemy's own weapons are turned against him. <em>Peruzav</em> (his warriors/those who rushed against me) — YHWH uses the enemy's own military strength against itself. The verse describes YHWH's battle-reversal tactic that appears throughout Israel's warfare theology: Israel does not fight; YHWH defeats the enemy through his own devices. The final phrase: <em>kesofam le'echol ani bestrom</em> — 'they came like a whirlwind to scatter me, rejoicing as if to devour the poor in secret.'</p>",

        "15": "<p><strong>darcheta vayam susecha chomer mayim rabbim</strong>: 'You trampled the sea with your horses, the surging of mighty waters.' The theophany concludes where it began — with the divine warrior on his chariot-horses treading through the sea. The Exodus crossing is the culmination of the vision: YHWH's battle chariot treads through the sea, the great chaos-waters, affirming his sovereign power over all that threatens his people. The theophany (vv3-15) moves from Sinai to the present Babylonian threat to the eschatological victory — one continuous divine battle for the salvation of his anointed.</p>",

        "16": "<p><strong>shamati vatirgazez bitni laqol tzalelu sefatai</strong>: 'I heard, and my body trembled; my lips quivered at the sound.' The transition from the theophanic vision (vv3-15) to personal response (vv16-19): the physical effect of the theophany on the prophet. <em>Vatirgazez bitni</em> (my body trembled, literally 'my belly quivered') — the visceral response to divine presence, like Daniel (Dan 8:27) and John (Rev 1:17) after visions. <em>Ve'acharish asher anuach leyom tzarah</em> — 'I quietly wait for the day of trouble to come upon people who invade us' — Habakkuk resolves to be still and wait (<em>anuach</em>, to rest) in the midst of impending judgment. The key: <em>leishuah el uf</em> (ascend to the people who will invade us) — awaiting YHWH's final victory.</p>",

        "17": "<p><strong>ki te'enah lo tifreach vein yevul bagefanim kichesh maase zayit</strong>: 'Though the fig tree should not blossom, nor fruit be on the vines, the produce of the olive fail and the fields yield no food.' The hypothetical of total agricultural collapse: the fig tree (<em>te'enah</em>), vines (<em>gefen</em>), olives (<em>zayit</em>), and fields (<em>shedamot</em>) are the four pillars of the Levantine agricultural economy, representing the covenantal abundance promised in Deuteronomy (Deut 8:7-8). Their total failure would mean the complete withdrawal of covenant blessing — the covenant curses of Deut 28 realized. Habakkuk's resolution to rejoice despite this ultimate negative scenario is the book's climactic statement of faith.</p>",

        "18": "<p><strong>va'ani baYHWH a'alozah agila be'elohei yishi</strong>: 'Yet I will rejoice in the LORD; I will take joy in the God of my salvation.' The emphatic <em>va'ani</em> (but I/yet I) sets Habakkuk apart from circumstances: regardless of the total agricultural collapse described in v17, his joy is grounded in YHWH and in the 'God of my salvation' (<em>elohei yishi</em>). The verb <em>a'alozah</em> (I will exult/rejoice, H5937) and <em>agila</em> (I will rejoice, H1523) are both strong verbs of celebration — not resigned contentment but active, exultant joy. The theological achievement of the book: the prophet moves from complaint about divine injustice (ch1) to joyful trust in the God of salvation (ch3:18) through the anchoring vision of divine sovereignty.</p>",

        "19": "<p><strong>YHWH Adonai cheli vayasem raglai kaayalot</strong>: 'God, the Lord, is my strength; he makes my feet like the deer's, and makes me tread on my high places.' The closing verse of the book combines military and pastoral imagery: <em>cheli</em> (my strength/army, H2428 — the same word as <em>chayil</em>, valor/force) — YHWH as the prophet's military strength. <em>Raglai kaayalot</em> (my feet like deer's feet) — the sure-footedness of the mountain deer on dangerous terrain; Ps 18:33 uses the same image for David after battle victories. <em>Vedarech bamotai</em> (he makes me tread on my high places/heights) — the prophet-as-watchman who climbed to his tower in 2:1 now treads confidently on the heights with divine strength. The postscript (<em>lamnatzeach bineginotai</em>, to the choirmaster, with my stringed instruments) frames the entire ch3 as a liturgical psalm — the theodicy of faith finds its natural home in worship.</p>"
    }
}


def main():
    c = load_comm('mkt-original', 'habakkuk')
    merge_comm(c, DATA)
    save_comm('mkt-original', 'habakkuk', c)
    total = sum(len(v) for v in DATA.values())
    print(f'habakkuk mkt-original: added up to {total} verses across ch1-3')


if __name__ == '__main__':
    main()
